import {
  ArrowLeft,
  MapPin,
  Clock,
  Mountain,
  TrendingUp,
  Loader2,
  ChevronRight,
  Star,
} from "lucide-react";
import { motion } from "framer-motion";
import { Header } from "../components/Header";
import { Footer } from "../components/Footer";
import { useLogoutHandler } from "../hooks/useLogoutHandler";
import LogoutModal from "../components/LogoutModal";

const API = "http://localhost:5000";

const difficultyColors = {
  Easy: "bg-emerald-100 text-emerald-700",
  Moderate: "bg-amber-100 text-amber-700",
  Difficult: "bg-orange-100 text-orange-700",
  Extreme: "bg-red-100 text-red-700",
};

const TrailDetail = () => {
  const { id } = useParams();
  const [trail, setTrail] = useState(null);
  const [loading, setLoading] = useState(true);
  const [selectedImage, setSelectedImage] = useState(0);
  const [user, setUser] = useState(null);

  const {
    handleLogout: originalHandleLogout,
    handleStayLoggedIn,
    showLogoutModal,
    setShowLogoutModal,
  } = useLogoutHandler();

  const handleLogout = () => {
    originalHandleLogout();
  };

  useEffect(() => {
    const token = sessionStorage.getItem("token");
    const userData = sessionStorage.getItem("user");
    if (token && userData) setUser(JSON.parse(userData));
  }, []);

  useEffect(() => {
    const fetchTrail = async () => {
      try {
        const res = await axios.get(`${API}/api/trails/public/${id}`);
        setTrail(res.data.trail);
      } catch (err) {
        console.error("Error fetching trail:", err);
      } finally {
        setLoading(false);
      }
    };
    fetchTrail();
  }, [id]);

  if (loading) {
    return (
      <div className="min-h-screen bg-cream flex items-center justify-center">
        <Loader2 className="h-10 w-10 animate-spin text-gold" />
      </div>
    );
  }

  if (!trail) {
    return (
      <div className="min-h-screen bg-cream flex flex-col items-center justify-center gap-4">
        <Mountain className="h-16 w-16 text-gray-300" />
        <h2 className="text-2xl font-bold text-charcoal">Trail Not Found</h2>
        <Link to="/" className="text-gold hover:text-gold-dark font-semibold flex items-center gap-1">
          <ArrowLeft className="h-4 w-4" /> Back to Home
        </Link>
      </div>
    );
  }

  const primaryImage = trail.images?.find((img) => img.is_primary);
  const heroImage = primaryImage
    ? `${API}${primaryImage.image_path}`
    : "https://images.unsplash.com/photo-1506905925346-21bda4d32df4?w=1200&q=80";

  const diff = difficultyColors[trail.difficulty_level] || difficultyColors["Moderate"];

  return (
    <div className="min-h-screen bg-cream">
      <Header user={user} onLogoutClick={() => setShowLogoutModal(true)} />

      {/* Hero Image */}
      <div className="relative h-[50vh] min-h-[400px] overflow-hidden">
        <img
          src={trail.images?.length > 0 ? `${API}${trail.images[selectedImage]?.image_path}` : heroImage}
          alt={trail.trail_name}
          className="w-full h-full object-cover"
        />
        <div className="absolute inset-0 bg-gradient-to-t from-charcoal/80 via-charcoal/30 to-transparent" />

        {/* Back button */}
        <Link
          to="/"
          className="absolute top-24 left-6 inline-flex items-center gap-2 px-4 py-2 bg-white/20 backdrop-blur-md rounded-xl text-white text-sm font-medium hover:bg-white/30 transition"
        >
          <ArrowLeft className="h-4 w-4" />
          Back to Trails
        </Link>

        {/* Title overlay */}
        <div className="absolute bottom-0 left-0 right-0 p-6 sm:p-10">
          <div className="max-w-5xl mx-auto">
            <span className={`inline-flex items-center gap-1.5 px-3 py-1 rounded-full text-xs font-bold ${diff} mb-3`}>
              <TrendingUp className="h-3 w-3" />
              {trail.difficulty_level}
            </span>
            <h1 className="text-3xl sm:text-4xl lg:text-5xl font-extrabold text-white mb-3 font-heading">
              {trail.trail_name}
            </h1>
            <div className="flex flex-wrap items-center gap-4 text-white/70 text-sm">
              <span className="flex items-center gap-1.5">
                <MapPin className="h-4 w-4 text-gold" />
                {trail.region}
              </span>
              <span className="flex items-center gap-1.5">
                <Clock className="h-4 w-4" />
                {trail.duration_days} Days
              </span>
              {trail.max_altitude && (
                <span className="flex items-center gap-1.5">
                  <Mountain className="h-4 w-4" />
                  {Number(trail.max_altitude).toLocaleString()}m
                </span>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* Image thumbnails */}
      {trail.images?.length > 1 && (
        <div className="max-w-5xl mx-auto px-4 sm:px-6 -mt-6 relative z-10">
          <div className="flex gap-3 overflow-x-auto pb-2">
            {trail.images.map((img, i) => (
              <button
                key={img.image_id}
                onClick={() => setSelectedImage(i)}
                className={`w-20 h-14 rounded-xl overflow-hidden flex-shrink-0 border-2 transition-all ${
                  selectedImage === i ? "border-gold shadow-lg" : "border-white/50 opacity-70 hover:opacity-100"
                }`}
              >
                <img
                  src={`${API}${img.image_path}`}
                  alt={`${trail.trail_name} ${i + 1}`}
                  className="w-full h-full object-cover"
                />
              </button>
            ))}
          </div>
        </div>
      )}

      {/* Content */}
      <div className="max-w-5xl mx-auto px-4 sm:px-6 py-12">
        <div className="grid lg:grid-cols-3 gap-10">
          {/* Main content */}
          <div className="lg:col-span-2 space-y-10">
            {/* Description */}
            <motion.div
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: 0.1 }}
            >
              <h2 className="text-2xl font-bold text-charcoal mb-4 font-heading">About This Trek</h2>
              <p className="text-gray-600 leading-relaxed whitespace-pre-line">{trail.description}</p>
            </motion.div>

            {/* Itinerary */}
            {trail.itineraries?.length > 0 && (
              <motion.div
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: 0.2 }}
              >
                <h2 className="text-2xl font-bold text-charcoal mb-6 font-heading">Day-by-Day Itinerary</h2>
                <div className="space-y-4">
                  {trail.itineraries.map((it) => (
                    <div
                      key={it.itinerary_id}
                      className="bg-white rounded-2xl p-5 border border-gray-100 shadow-sm hover:shadow-md transition-shadow"
                    >
                      <div className="flex items-center gap-3 mb-3">
                        <span className="inline-flex items-center justify-center w-10 h-10 rounded-xl bg-gold/10 text-gold font-extrabold text-sm">
                          {it.day_number}
                        </span>
                        <div>
                          <p className="text-xs text-gray-400 uppercase tracking-widest font-semibold">Day {it.day_number}</p>
                          {it.title && <p className="text-base font-bold text-charcoal">{it.title}</p>}
                        </div>
                      </div>
                      <p className="text-gray-600 text-sm leading-relaxed mb-3">{it.description}</p>
                      <div className="flex flex-wrap gap-4 text-xs text-gray-400">
                        {it.altitude && (
                          <span className="flex items-center gap-1">
                            <Mountain className="h-3.5 w-3.5 text-gold" />
                            {Number(it.altitude).toLocaleString()}m
                          </span>
                        )}
                        {it.distance_km && (
                          <span className="flex items-center gap-1">
                            <MapPin className="h-3.5 w-3.5" />
                            {it.distance_km} km
                          </span>
                        )}
                        {it.walking_hours && (
                          <span className="flex items-center gap-1">
                            <Clock className="h-3.5 w-3.5" />
                            {it.walking_hours} hrs walking
                          </span>
                        )}
                      </div>
                    </div>
                  ))}
                </div>
              </motion.div>
            )}
          </div>

          {/* Side info card */}
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.3 }}
            className="lg:col-span-1"
          >
            <div className="bg-white rounded-2xl p-6 border border-gray-100 shadow-md sticky top-28 space-y-5">
              <h3 className="text-lg font-bold text-charcoal">Trek Details</h3>

              <div className="space-y-4">
                <div className="flex items-center justify-between py-3 border-b border-gray-100">
                  <span className="text-sm text-gray-500">Region</span>
                  <span className="text-sm font-semibold text-charcoal flex items-center gap-1">
                    <MapPin className="h-3.5 w-3.5 text-gold" />
                    {trail.region}
                  </span>
                </div>
                <div className="flex items-center justify-between py-3 border-b border-gray-100">
                  <span className="text-sm text-gray-500">Duration</span>
                  <span className="text-sm font-semibold text-charcoal">{trail.duration_days} Days</span>
                </div>
                <div className="flex items-center justify-between py-3 border-b border-gray-100">
                  <span className="text-sm text-gray-500">Difficulty</span>
                  <span className={`text-xs font-bold px-3 py-1 rounded-full ${diff}`}>
                    {trail.difficulty_level}
                  </span>
                </div>
                {trail.max_altitude && (
                  <div className="flex items-center justify-between py-3 border-b border-gray-100">
                    <span className="text-sm text-gray-500">Max Altitude</span>
                    <span className="text-sm font-semibold text-charcoal">
                      {Number(trail.max_altitude).toLocaleString()}m
                    </span>
                  </div>
                )}
              </div>

              <Link
                to="/register"
                className="w-full inline-flex items-center justify-center gap-2 px-6 py-3.5 text-base font-bold text-navy rounded-xl shadow-lg shadow-gold/25 hover:shadow-xl hover:shadow-gold/40 hover:scale-[1.02] transition-all duration-300"
                style={{
                  background: "linear-gradient(135deg, #C8932A 0%, #E0B04A 100%)",
                }}
              >
                Book This Trek
                <ChevronRight className="h-5 w-5" />
              </Link>

              <p className="text-xs text-center text-gray-400">
                Free cancellation up to 48 hours before departure
              </p>
            </div>
          </motion.div>
        </div>
      </div>

      <Footer />

      <LogoutModal
        isOpen={showLogoutModal}
        onConfirm={handleLogout}
        onCancel={handleStayLoggedIn}
      />
    </div>
  );
};

export default TrailDetail;
